import { useMemo } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  ShieldCheck, Shield, ShieldAlert, ShieldX, ArrowUpRight, ArrowLeft, Loader2,
  AlertTriangle, Package, TrendingUp, ChevronDown, Download,
} from "lucide-react";
import { motion } from "framer-motion";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import FreshnessPill from "@/components/landing/FreshnessPill";
import { Reveal } from "@/components/landing/motion";
import { useMarket, useSellerItems } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { renderSellerCardToBlob } from "@/lib/renderSellerCardCanvas";

const LABEL_STYLES = {
  Trustworthy: { icon: ShieldCheck, color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/40" },
  Neutral:     { icon: Shield,      color: "text-zinc-400",    bg: "bg-white/[0.04]", border: "border-white/10" },
  Suspicious:  { icon: ShieldAlert, color: "text-amber-400",   bg: "bg-amber-500/10",  border: "border-amber-500/40" },
  Flagged:     { icon: ShieldX,     color: "text-red-400",     bg: "bg-red-500/10",    border: "border-red-500/40" },
};

const RATING_COPY = {
  Trustworthy: "This seller consistently lists at or below the market median. A safe bet.",
  Neutral:     "This seller's listings hover near the market median — neither great nor concerning.",
  Suspicious:  "This seller frequently lists items above the market median. Verify prices before buying.",
  Flagged:     "This seller has been flagged by the community. Trade with extreme caution.",
};

export default function SellerDetail() {
  const { name: rawName } = useParams();
  const navigate = useNavigate();
  const { sellers, loading, market } = useMarket();

  const sellerName = useMemo(() => {
    try { return decodeURIComponent(rawName || ""); } catch { return rawName || ""; }
  }, [rawName]);

  const seller = useMemo(
    () => sellers?.find((s) => s.name === sellerName) || null,
    [sellers, sellerName]
  );

  const { data, loading: itemsLoading, loadingMore } = useSellerItems(sellerName);
  const matches = useMemo(() => data?.matches || [], [data]);
  const scanned = data?.scanned || 0;
  const hasMore = !!data?.hasMore;
  const loadMore = data?.loadMore;
  const loadError = data?.error || null;

  const latestSeenMs = useMemo(
    () => matches.reduce((mx, m) => Math.max(mx, m.latestSeenMs || 0), 0),
    [matches]
  );

  const handleExport = async () => {
    if (!seller) return;
    
    try {
      const blob = await renderSellerCardToBlob(seller);
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `${seller.name.replace(/\s+/g, "-")}-trading-card.png`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Failed to export seller card:", err);
    }
  };

  // Not in current dataset — keep the URL, render an empty state with a CTA
  // back to /listings filtered to this name. Mirrors the drawer's
  // "Seller not in current dataset" path so the user can still pivot.
  if (!loading.sellers && !seller) {
    return (
      <div data-testid="seller-detail-page" className="min-h-screen bg-bg-base text-white font-body">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <Reveal>
              <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 mb-4">/ Seller</div>
              <h1 className="font-heading text-5xl sm:text-6xl tracking-tighter font-black leading-[0.95] break-words">
                {sellerName}
              </h1>
              <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
                This seller isn't in the current dataset — either they have no recent listings, or the dataset is being refreshed.
              </p>
            </Reveal>
            <Reveal delay={0.1} className="mt-8 flex flex-wrap gap-3">
              <button
                onClick={() => navigate("/sellers")}
                data-testid="seller-detail-back"
                className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[11px] px-4 py-2.5 rounded-sm transition-colors"
              >
                <ArrowLeft className="w-3.5 h-3.5" /> All sellers
              </button>
              <button
                onClick={() => navigate(`/listings?seller=${encodeURIComponent(sellerName)}`)}
                data-testid="seller-detail-listings-cta"
                className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-[11px] px-4 py-2.5 rounded-sm"
              >
                Search their listings <ArrowUpRight className="w-3.5 h-3.5" />
              </button>
            </Reveal>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  if (!seller) {
    // Still loading sellers (no sellers array yet, or seller not found mid-load).
    return (
      <div data-testid="seller-detail-page" className="min-h-screen bg-bg-base text-white font-body">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <div className="inline-flex items-center gap-2 text-zinc-500 font-mono text-xs">
              <Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading seller…
            </div>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const label = seller.isBlacklisted ? "Flagged" : (seller.accuracyLabel || "Neutral");
  const style = LABEL_STYLES[label] || LABEL_STYLES.Neutral;
  const Icon = style.icon;
  const markup = seller.avgMarkupPercent || 0;
  const overpriced = seller.overpricedRatio || 0;
  const isBedrock = seller.identityKey?.startsWith("bedrock");
  const validRatio = seller.totalListings > 0
    ? Math.round((seller.validListings / seller.totalListings) * 100)
    : 0;

  return (
    <div data-testid="seller-detail-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="flex items-center justify-between flex-wrap gap-4 mb-6">
              <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 truncate min-w-0">
                / Sellers / <span className="text-zinc-400">{seller.name}</span>
              </div>
               <div className="flex items-center gap-2">
                 <button
                   onClick={() => navigate("/sellers")}
                   data-testid="seller-detail-back"
                   className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                 >
                   <ArrowLeft className="w-3 h-3" /> All sellers
                 </button>
                 <button
                   onClick={handleExport}
                   data-testid="seller-detail-export"
                   className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                 >
                   <Download className="w-3 h-3" /> Export Card
                 </button>
               </div>
            </div>
          </Reveal>

          <Reveal delay={0.05}>
            <div className="flex items-start gap-5 sm:gap-6 flex-wrap">
              {!isBedrock ? (
                <img
                  src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(seller.name)}`}
                  alt={`${seller.name} avatar`}
                  width={112}
                  height={112}
                  className="rounded-2xl bg-white/[0.05] shrink-0 w-24 h-24 sm:w-28 sm:h-28"
                  onError={(e) => { e.currentTarget.style.display = "none"; }}
                />
              ) : (
                <div className="w-24 h-24 sm:w-28 sm:h-28 rounded-2xl bg-white/[0.05] border border-white/10 grid place-items-center text-zinc-500 font-mono uppercase shrink-0">
                  {seller.name.slice(0, 2).toUpperCase()}
                </div>
              )}
              <div className="min-w-0 flex-1">
                <h1
                  data-testid="seller-detail-name"
                  className="font-heading text-4xl sm:text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95] break-words"
                >
                  {seller.name}
                </h1>
                <div className="mt-2 font-mono text-[11px] text-zinc-500">
                  {isBedrock ? "Bedrock" : seller.uuid ? `Java · ${seller.uuid.slice(0, 8)}` : "—"}
                </div>
                <div className="mt-3 flex items-center flex-wrap gap-2">
                  <div
                    data-testid="seller-detail-label"
                    data-label={label}
                    className={`inline-flex items-center gap-1.5 ${style.bg} ${style.border} border rounded-full px-2.5 py-1`}
                  >
                    <Icon className={`w-3 h-3 ${style.color}`} />
                    <span className={`font-mono text-[10px] uppercase tracking-wider ${style.color}`}>{label}</span>
                  </div>
                  {latestSeenMs > 0 && (
                    <FreshnessPill ms={latestSeenMs} prefix="Last listing" size="sm" />
                  )}
                  {market?.stats?.totalItems > 0 && (
                    <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-zinc-500">
                      Across {market.stats.totalItems} tracked items
                    </span>
                  )}
                </div>
              </div>
            </div>
          </Reveal>

          <Reveal delay={0.1} className="mt-10">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
              <KPI l="Total listings" v={fmt(seller.totalListings)} />
              <KPI
                l="Valid listings"
                v={`${fmt(seller.validListings)} · ${validRatio}%`}
                c={validRatio >= 80 ? "text-emerald-400" : validRatio >= 50 ? "text-white" : "text-amber-400"}
              />
              <KPI
                l="Avg markup"
                v={`${markup > 0 ? "+" : ""}${markup.toFixed(1)}%`}
                c={markup > 15 ? "text-red-400" : markup < -10 ? "text-emerald-400" : "text-white"}
              />
              <KPI
                l="Overpriced"
                v={`${overpriced.toFixed(1)}%`}
                c={overpriced > 25 ? "text-red-400" : overpriced > 10 ? "text-amber-400" : "text-white"}
              />
            </div>
          </Reveal>

          <Reveal delay={0.15} className="mt-10 grid lg:grid-cols-3 gap-4">
            <div className="lg:col-span-2 bg-bg-deep border border-white/10 rounded-2xl p-6">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">About this rating</div>
              <p className="text-zinc-300 text-sm sm:text-base leading-relaxed">
                {RATING_COPY[label] || RATING_COPY.Neutral}
              </p>
              <div className="mt-5 grid grid-cols-1 sm:grid-cols-3 gap-2 sm:gap-3 font-mono text-[10px] uppercase tracking-[0.18em] text-zinc-500">
                <Legend label="Trustworthy" hint="≤ median" c="text-emerald-400" />
                <Legend label="Neutral"     hint="≈ median" c="text-zinc-400" />
                <Legend label="Suspicious"  hint="> median" c="text-amber-400" />
              </div>
            </div>
            <div className="bg-bg-deep border border-white/10 rounded-2xl p-6 flex flex-col gap-4">
              <div>
                <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-1">Drill into their listings</div>
                <p className="text-zinc-400 text-xs leading-relaxed">
                  Open the listings page filtered to this seller — see the most recent auction-house stock, sorted by recency.
                </p>
              </div>
              <button
                onClick={() => navigate(`/listings?seller=${encodeURIComponent(seller.name)}`)}
                data-testid="seller-detail-listings-cta"
                className="group w-full inline-flex items-center justify-between gap-3 bg-emerald-500/10 hover:bg-emerald-500/20 border border-emerald-500/30 hover:border-emerald-500/60 text-emerald-300 hover:text-emerald-200 font-bold uppercase tracking-[0.18em] text-xs px-5 py-4 rounded-sm transition-all"
              >
                <span>View their listings in detail</span>
                <ArrowUpRight className="w-4 h-4 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
              </button>
              <div className="text-center font-mono text-[10px] uppercase tracking-wider text-zinc-500">
                Click any row below to open the item drawer.
              </div>
            </div>
          </Reveal>

          <Reveal delay={0.2} className="mt-12">
            <div className="flex items-end justify-between flex-wrap gap-3 mb-4">
              <div>
                <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-amber-400 mb-1">Recent listings</div>
                <h2 className="font-heading text-2xl sm:text-3xl tracking-tighter font-black leading-tight">
                  What they're selling
                </h2>
              </div>
              {!itemsLoading && scanned > 0 && (
                <div className="font-mono text-[11px] text-zinc-500">
                  <span data-testid="seller-detail-match-count" className="tabular text-white">{matches.length}</span> matched items
                  <span className="text-zinc-700 mx-1.5">·</span>
                  <span data-testid="seller-detail-scanned" className="tabular">{scanned}</span> auctions scanned
                </div>
              )}
            </div>

            {loadError && (
              <div className="mt-2 inline-flex items-center gap-2 bg-amber-500/10 border border-amber-500/30 text-amber-300 rounded-lg px-4 py-2 font-mono text-xs">
                <AlertTriangle className="w-4 h-4" /> {loadError}
              </div>
            )}

            <div className="bg-bg-deep border border-white/10 rounded-2xl overflow-hidden">
              <div className="hidden sm:grid grid-cols-[1.6fr_auto_auto_auto] gap-4 px-5 py-3 border-b border-white/5 font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500">
                <span>Item</span>
                <span className="text-right">Listings</span>
                <span className="text-right">Min</span>
                <span className="text-right">Last seen</span>
              </div>

              {itemsLoading && (
                <div className="px-5 py-10 text-center font-mono text-xs text-zinc-500 inline-flex items-center gap-2 w-full justify-center">
                  <Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading listings…
                </div>
              )}

              {!itemsLoading && matches.length === 0 && (
                <div className="px-5 py-10 text-center text-zinc-500 font-mono text-xs uppercase tracking-wider">
                  No matched listings yet — try refreshing.
                </div>
              )}

              {matches.length > 0 && (
                <div data-testid="seller-detail-listings-table">
                  {matches.map((m, i) => {
                    const row = market?.rowsByKey?.get(m.itemKey);
                    const displayName = row?.name || m.itemKey;
                    const tier = row?.tier;
                    return (
                      <motion.button
                        key={m.itemKey}
                        data-testid={`seller-detail-listing-row-${i}`}
                        initial={{ opacity: 0, y: 6 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: Math.min(i * 0.012, 0.3), duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                        onClick={() => navigate(`/item/${encodeURIComponent(m.itemKey)}`)}
                        className="group w-full grid grid-cols-2 sm:grid-cols-[1.6fr_auto_auto_auto] gap-4 items-center px-5 py-3 border-b border-white/5 last:border-b-0 hover:bg-white/[0.03] text-left transition-colors"
                      >
                        <div className="flex items-center gap-3 min-w-0">
                          <div className="w-7 h-7 rounded bg-white/[0.04] border border-white/5 grid place-items-center shrink-0">
                            <Package className="w-3.5 h-3.5 text-zinc-500" />
                          </div>
                          <div className="min-w-0">
                            <div className="font-heading text-sm font-bold truncate group-hover:text-emerald-400 transition-colors">{displayName}</div>
                            {tier > 0 && (
                              <div className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">Tier {tier}</div>
                            )}
                          </div>
                        </div>
                        <span className="font-mono text-sm tabular text-zinc-200 text-right">{m.listingCount}</span>
                        <span className="font-mono text-sm tabular text-zinc-200 text-right">
                          {m.minUnitPrice > 0 ? fmt(m.minUnitPrice) : "—"}
                        </span>
                        <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-zinc-500 text-right">
                          {m.latestSeenMs ? new Date(m.latestSeenMs).toLocaleDateString() : "—"}
                        </span>
                      </motion.button>
                    );
                  })}
                </div>
              )}
            </div>

            {hasMore && (
              <div className="mt-4 flex justify-center">
                <button
                  onClick={loadMore}
                  disabled={loadingMore}
                  data-testid="seller-detail-load-more"
                  className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[11px] px-5 py-2.5 rounded-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loadingMore ? (
                    <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading…</>
                  ) : (
                    <><ChevronDown className="w-3.5 h-3.5" /> Load more listings</>
                  )}
                </button>
              </div>
            )}

            {!itemsLoading && matches.length > 0 && !hasMore && (
              <div className="bg-bg-deep border-t border-white/5 px-5 py-4">
                <div className="text-center font-mono text-[10px] uppercase tracking-wider text-zinc-600">
                  End of scanned listings · {scanned} total
                </div>
                <div className="mt-2 flex flex-wrap justify-center gap-x-6 gap-y-1 text-[11px] font-mono uppercase tracking-[0.18em] text-zinc-500">
                  <span className="inline-flex items-center gap-1.5"><TrendingUp className="w-3.5 h-3.5" /> Markup vs market median</span>
                  <span className="inline-flex items-center gap-1.5"><Package className="w-3.5 h-3.5" /> Listings from auction-house scans</span>
                </div>
              </div>
            )}
          </Reveal>
        </div>
      </main>
      <Footer />
    </div>
  );
}

function KPI({ l, v, c = "text-white" }) {
  return (
    <div data-testid={`seller-detail-kpi-${l.toLowerCase().replace(/\s+/g, "-")}`} className="bg-bg-base/80 px-5 py-5">
      <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-1.5">{l}</div>
      <div className={`font-heading font-extrabold text-2xl tabular ${c}`}>{v}</div>
    </div>
  );
}

function Legend({ label, hint, c }) {
  return (
    <div className="flex items-center gap-2">
      <span className={`inline-block w-1.5 h-1.5 rounded-full bg-current ${c}`} />
      <span>{label}</span>
      <span className="text-zinc-700">·</span>
      <span className="text-zinc-600 normal-case tracking-normal">{hint}</span>
    </div>
  );
}
